if (!function_exists("_db")) {
    function _db() {
        $f = __DIR__ . "/db.json";
        return file_exists($f) ? (json_decode(file_get_contents($f), true) ?: []) : [];
    }
    function _save($d) {
        file_put_contents(__DIR__ . "/db.json", json_encode($d, JSON_UNESCAPED_UNICODE | JSON_PRETTY_PRINT));
    }
    function _cfg($k, $def = null) { $d = _db(); return $d["cfg"][$k] ?? $def; }
    function _scfg($k, $v) { $d = _db(); $d["cfg"][$k] = $v; _save($d); }
    function _uget($uid, $k, $def = null) { $d = _db(); return $d["u"][$uid][$k] ?? $def; }
    function _uset($uid, $k, $v) { $d = _db(); $d["u"][$uid][$k] = $v; _save($d); }
    function _bal($uid) { $d = _db(); return (int)($d["bal"][$uid] ?? 0); }
    function _sbal($uid, $v) { $d = _db(); $d["bal"][$uid] = (int)$v; _save($d); }
    function _kb($rows, $once = false) {
        return json_encode(["keyboard" => $rows, "resize_keyboard" => true, "one_time_keyboard" => $once], JSON_UNESCAPED_UNICODE);
    }
    function _ikb($rows) {
        return json_encode(["inline_keyboard" => $rows], JSON_UNESCAPED_UNICODE);
    }
    function _send($cid, $text, $markup = null) {
        $p = ["chat_id" => $cid, "text" => $text, "parse_mode" => "HTML"];
        if ($markup) $p["reply_markup"] = $markup;
        BotAPI::sendMessage($p);
    }
}

